namespace BgControls.Windows.Input.Touch;/// <summary>/// 捏合操作信息类，用于记录和管理捏合手势中单个触控点的状态./// </summary>internal class PinchInfo{    private int touchId;    private UIElement element;    private Action<PinchInfo, TouchDevice>? onLostTouchCapture;    private TouchDevice? capturedTouchDevice;    /// <summary>    /// Initializes a new instance of the <see cref="PinchInfo"/> class.    /// </summary>    /// <param name="element">关联的 UI 元素.</param>    /// <param name="touchId">触控 ID.</param>    /// <param name="position">初始触控位置.</param>    /// <param name="touchEventArgs">触控事件参数.</param>    /// <param name="onLostTouchCapture">丢失触控捕获时的回调动作.</param>    public PinchInfo(        UIElement element,        int touchId,        Point position,        BgControls.Windows.Input.Touch.TouchEventArgs touchEventArgs,        Action<PinchInfo, TouchDevice>? onLostTouchCapture)    {        // 设置内部字段和属性的初始值.        this.element = element;        this.touchId = touchId;        this.onLostTouchCapture = onLostTouchCapture;        this.LastTouchMovePosition = position;        this.PivotPosition = position;        this.TouchEventArgs = touchEventArgs;    }    /// <summary>    /// Gets 触控 ID.    /// </summary>    public int TouchId => this.touchId;    /// <summary>    /// Gets or sets 上次触控移动位置.    /// </summary>    public Point LastTouchMovePosition { get; set; }    /// <summary>    /// Gets or sets 枢轴（起始）位置.    /// </summary>    public Point PivotPosition { get; set; }    /// <summary>    /// Gets or sets 触控事件参数.    /// </summary>    public BgControls.Windows.Input.Touch.TouchEventArgs TouchEventArgs { get; set; }    /// <summary>    /// 释放当前持有的触控捕获.    /// </summary>    public void ReleaseTouchCapture()    {        // 备份当前捕获的设备并清空引用.        TouchDevice? currentDevice = this.capturedTouchDevice;        if (currentDevice != null)        {            this.capturedTouchDevice = null;            // 移除丢失捕获的监听并执行释放逻辑.            TouchManager.RemoveLostTouchCaptureHandler(this.element, this.OnLostTouchCapture);            TouchManager.ReleaseTouchCapture(this.element, currentDevice);        }    }    /// <summary>    /// 尝试捕获指定的触控设备.    /// </summary>    /// <param name="touchDevice">待捕获的触控设备.</param>    /// <returns>如果捕获成功则返回 true; 否则返回 false.</returns>    public bool TryCaptureTouch(TouchDevice touchDevice)    {        // 检查设备当前是否已被其他元素捕获.        if (TouchManager.GetCaptured(touchDevice) == null)        {            // 执行捕获逻辑并注册丢失捕获的监听.            if (TouchManager.CaptureTouch(this.element, touchDevice))            {                this.capturedTouchDevice = touchDevice;                TouchManager.AddLostTouchCaptureHandler(this.element, this.OnLostTouchCapture);                return true;            }            return false;        }        return false;    }    /// <summary>    /// 响应系统丢失触控捕获的事件回调.    /// </summary>    /// <param name="sender">事件发送者.</param>    /// <param name="lostTouchCaptureArgs">丢失捕获的事件参数.</param>    private void OnLostTouchCapture(object sender, BgControls.Windows.Input.Touch.TouchEventArgs lostTouchCaptureArgs)    {        // 校验丢失捕获的设备 ID 是否匹配当前记录的 ID.        if (this.touchId == lostTouchCaptureArgs.TouchDevice.Id)        {            // 执行外部传入的回调动作.            this.onLostTouchCapture?.Invoke(this, lostTouchCaptureArgs.TouchDevice);            // 确保本地状态和监听被正确清理.            this.ReleaseTouchCapture();        }    }}